```python
import os
import csv
import logging
from concurrent.futures import ThreadPoolExecutor
from PyPDF2 import PdfFileReader
from tabula import read_pdf
from pytesseract import image_to_string
from PIL import Image

# Set up logging
logging.basicConfig(level=logging.DEBUG, format='%(asctime)s - %(levelname)s - %(message)s')

# Define function to extract text from PDF
def extract_text(pdf_file):
    try:
        with open(pdf_file, 'rb') as f:
            pdf = PdfFileReader(f)
            text = ''
            for page in range(pdf.getNumPages()):
                text += pdf.getPage(page).extractText()
        return text
    except Exception as e:
        logging.error(f'Error extracting text from {pdf_file}: {e}')
        return None

# Define function to extract tables from PDF
def extract_tables(pdf_file):
    try:
        tables = read_pdf(pdf_file, pages='all')
        return tables
    except Exception as e:
        logging.error(f'Error extracting tables from {pdf_file}: {e}')
        return None

# Define function to extract text from scanned image
def extract_text_from_image(image_file):
    try:
        image = Image.open(image_file)
        text = image_to_string(image)
        return text
    except Exception as e:
        logging.error(f'Error extracting text from {image_file}: {e}')
        return None

# Define function to process PDF file
def process_pdf(pdf_file):
    text = extract_text(pdf_file)
    if text is None:
        return None
    tables = extract_tables(pdf_file)
    if tables is None:
        return None
    return (text, tables)

# Define function to process image file
def process_image(image_file):
    text = extract_text_from_image(image_file)
    if text is None:
        return None
    return (text, None)

# Define function to process file
def process_file(file):
    if file.endswith('.pdf'):
        return process_pdf(file)
    elif file.endswith('.jpg') or file.endswith('.png'):
        return process_image(file)
    else:
        return None

# Define function to write to CSV file
def write_to_csv(data, output_file):
    with open(output_file, 'w', newline='', encoding='utf-8') as f:
        writer = csv.writer(f)
        writer.writerow(['File', 'Text', 'Tables'])
        for file, (text, tables) in data.items():
            writer.writerow([file, text, tables])

# Define function to process directory
def process_directory(directory, output_file):
    files = [os.path.join(directory, f) for f in os.listdir(directory)]
    data = {}
    with ThreadPoolExecutor() as executor:
        for file, result in zip(files, executor.map(process_file, files)):
            if result is not None:
                data[file] = result
    write_to_csv(data, output_file)

# Example usage
